return [{ json: {
  feedIds: [142, 152, 161],
  dedupThreshold: 0.5,
  snippetWords: 40,
  sections: ['week', 'month'],
  maxItems: { week: 5, month: 6 },
  maxWordsPerBullet: 22,
  systemPrompt: 'You write ultra-concise dashboard digests as JSON.',
  userPromptTemplate: 'Build an "AI" digest as JSON from AI news articles. Focus on major trends and genuine innovations: new model capabilities, research breakthroughs, significant tooling or infrastructure shifts, and industry-shaping moves. Skip incremental product updates, funding gossip, and hype pieces. "week": at most {{MAX_WEEK}} bullets covering the most significant developments from the past 7 days. "month": at most {{MAX_MONTH}} bullets covering the broader trends and most important stories from 8-30 days ago -- a separate, older set of articles listed below, so there is no overlap with "week" by construction. Before writing, group the source articles by shared model, company, or theme and write ONE bullet per group covering all its articles together -- do not write one bullet per article. Each bullet is ONE plain sentence, {{MAX_WORDS}} words max, rewritten in your own words -- never copy article text, no dates, no markers.\n\nPast 7 days:\n{{WEEK_ENTRIES}}\n\n8-30 days ago:\n{{MONTH_ENTRIES}}'
} }];

function tokens(t) {
  return new Set((t || '').toLowerCase().replace(/[^a-z0-9 ]/g, '').split(' ').filter(w => w.length > 3));
}
function similarity(a, b) {
  const ta = tokens(a), tb = tokens(b);
  const inter = [...ta].filter(w => tb.has(w)).length;
  return inter / Math.max(ta.size, tb.size, 1);
}
const cfg = $('Config').first().json;
const cutoffMs = $now.minus({ days: 7 }).toMillis();
const entries = $input.all().map(i => i.json).sort((a, b) => new Date(b.published_at) - new Date(a.published_at));
const buckets = { week: [], month: [] };
for (const e of entries) {
  const bucket = new Date(e.published_at).getTime() >= cutoffMs ? 'week' : 'month';
  if (buckets[bucket].some(k => similarity(k.title, e.title) > cfg.dedupThreshold)) continue;
  buckets[bucket].push(e);
}
const out = [];
for (const bucket of ['week', 'month']) {
  for (const e of buckets[bucket]) {
    out.push({ json: {
      bucket,
      title: e.title,
      published_at: e.published_at,
      snippet: (e.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().split(' ').slice(0, cfg.snippetWords).join(' ')
    } });
  }
}
if (!out.length) throw new Error('no entries in the last 30 days');
return out;

const cfg = $('Config').first().json;
const items = $input.all().map(i => i.json);
const fmt = list => list.map(e => `- ${e.title} (${e.published_at.slice(0, 10)}): ${e.snippet}`).join('\n') || '(none)';
const weekEntries = fmt(items.filter(e => e.bucket === 'week'));
const monthEntries = fmt(items.filter(e => e.bucket === 'month'));
let userPrompt = cfg.userPromptTemplate
  .replaceAll('{{MAX_WORDS}}', cfg.maxWordsPerBullet)
  .replaceAll('{{WEEK_ENTRIES}}', weekEntries)
  .replaceAll('{{MONTH_ENTRIES}}', monthEntries);
for (const name of cfg.sections) {
  userPrompt = userPrompt.replaceAll(`{{MAX_${name.toUpperCase()}}}`, cfg.maxItems[name]);
}
const properties = Object.fromEntries(cfg.sections.map(name => [name, { type: 'array', items: { type: 'string' } }]));
const payload = {
  model: 'qwen3.5-9b',
  temperature: 0.3,
  max_tokens: 2048,
  chat_template_kwargs: { enable_thinking: false },
  response_format: { type: 'json_schema', json_schema: { name: 'digest', schema: { type: 'object', properties, required: cfg.sections } } },
  messages: [
    { role: 'system', content: cfg.systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};
return [{ json: { payload } }];

function tokens(t) {
  return new Set((t || '').toLowerCase().replace(/[^a-z0-9 ]/g, '').split(' ').filter(w => w.length > 3));
}
function similarity(a, b) {
  const ta = tokens(a), tb = tokens(b);
  const inter = [...ta].filter(w => tb.has(w)).length;
  return inter / Math.max(ta.size, tb.size, 1);
}
const cfg = $('Config').first().json;
const raw = JSON.parse($input.first().json.choices[0].message.content);
function clean(list, max) {
  const kept = [];
  for (const item of (list || [])) {
    if (kept.some(k => similarity(k, item) > 0.6)) continue;
    kept.push(item);
    if (kept.length >= max) break;
  }
  return kept;
}
const result = Object.fromEntries(cfg.sections.map(name => [name, clean(raw[name], cfg.maxItems[name])]));
if (Object.values(result).every(list => !list.length)) throw new Error('QA: digest empty after cleanup');
return [{ json: result }];

const d = $input.first().json;
const s = $getWorkflowStaticData('global');
s.digest = { week: d.week, month: d.month, updated: $now.toISO() };
return [{ json: s.digest }];
